{
  "name": "Finanza503020",
  "description": "Una aplicación inteligente de finanzas personales basada en el método 50/30/20 para ayudarte a gestionar tus necesidades, deseos y ahorros con consejos impulsados por IA."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Category {
  NEEDS = 'NEEDS',
  WANTS = 'WANTS',
  SAVINGS = 'SAVINGS'
}

export enum Frequency {
  MONTHLY = 'MONTHLY',
  BIWEEKLY = 'BIWEEKLY',
  WEEKLY = 'WEEKLY'
}

export interface Expense {
  id: string;
  amount: number;
  category: Category;
  description: string;
  date: string;
}

export interface UserProfile {
  income: number;
  frequency: Frequency;
  currency: string;
  streak: number;
  lastLoginDate: string;
}

export interface BudgetSplit {
  needs: number;
  wants: number;
  savings: number;
}

export const CATEGORY_LABELS = {
  NEEDS: 'Necesidades (50%)',
  WANTS: 'Deseos (30%)',
  SAVINGS: 'Ahorro/Deuda (20%)'
};

export const FREQUENCY_LABELS = {
  MONTHLY: 'Mensual',
  BIWEEKLY: 'Quincenal',
  WEEKLY: 'Semanal'
};

export const CATEGORY_COLORS = {
  NEEDS: '#6366f1', // Indigo
  WANTS: '#f43f5e', // Rose
  SAVINGS: '#10b981' // Emerald
};

import { GoogleGenAI } from "@google/genai";
import { UserProfile, Expense } from "../types";

export const getFinancialAdvice = async (profile: UserProfile, expenses: Expense[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const totalExpenses = expenses.reduce((acc, curr) => acc + curr.amount, 0);
  const prompt = `
    Actúa como un asesor financiero experto. El usuario tiene un ingreso ${profile.frequency.toLowerCase()} de ${profile.income} ${profile.currency}.
    Sigue el método 50/30/20.
    Gastos totales registrados hasta ahora: ${totalExpenses}.
    Gastos detallados: ${JSON.stringify(expenses.slice(-5))}.

    Genera 3 consejos prácticos, cortos y motivadores en español para este usuario. 
    Uno sobre cómo ahorrar más, otro sobre primeros pasos en inversión y uno sobre control de gastos.
    Devuelve la respuesta en formato JSON con la siguiente estructura:
    {
      "tips": [
        {"title": "string", "content": "string", "category": "ahorro" | "inversion" | "gasto"}
      ]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json"
      }
    });

    const data = JSON.parse(response.text || '{"tips": []}');
    return data.tips;
  } catch (error) {
    console.error("Error fetching tips:", error);
    return [];
  }
};

import React, { useState } from 'react';
import { Frequency } from '../types';

interface OnboardingProps {
  onComplete: (income: number, frequency: Frequency) => void;
}

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [income, setIncome] = useState<string>('');
  const [frequency, setFrequency] = useState<Frequency>(Frequency.MONTHLY);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numIncome = parseFloat(income);
    if (isNaN(numIncome) || numIncome <= 0) return;
    onComplete(numIncome, frequency);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-600 to-emerald-500 p-4">
      <div className="bg-white rounded-3xl shadow-2xl p-8 w-full max-w-md">
        <div className="text-center mb-8">
          <div className="bg-indigo-100 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 1.343-3 3s1.343 3 3 3 3-1.343 3-3-1.343-3-3-3z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 2a10 10 0 100 20 10 10 0 000-20zM12 2v2m0 16v2m10-10h-2M4 10H2" />
            </svg>
          </div>
          <h1 className="text-2xl font-bold text-slate-800">¡Bienvenido a Finanza503020!</h1>
          <p className="text-slate-500 mt-2">Configura tu plan de libertad financiera hoy.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">¿Cuál es tu ingreso neto?</label>
            <div className="relative">
              <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">$</span>
              <input
                type="number"
                required
                value={income}
                onChange={(e) => setIncome(e.target.value)}
                className="w-full pl-8 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                placeholder="0.00"
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">Frecuencia de cobro</label>
            <div className="grid grid-cols-3 gap-2">
              {[
                { val: Frequency.WEEKLY, label: 'Semanal' },
                { val: Frequency.BIWEEKLY, label: 'Quincenal' },
                { val: Frequency.MONTHLY, label: 'Mensual' }
              ].map((opt) => (
                <button
                  key={opt.val}
                  type="button"
                  onClick={() => setFrequency(opt.val)}
                  className={`py-2 px-1 text-xs font-semibold rounded-lg border transition-all ${
                    frequency === opt.val
                      ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg'
                      : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-300'
                  }`}
                >
                  {opt.label}
                </button>
              ))}
            </div>
          </div>

          <button
            type="submit"
            className="w-full bg-slate-900 text-white font-bold py-4 rounded-xl hover:bg-slate-800 transform active:scale-95 transition-all shadow-xl"
          >
            Empezar a Ahorrar
          </button>
        </form>
      </div>
    </div>
  );
};

export default Onboarding;

import React from 'react';
import { UserProfile, Expense, Category } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { CATEGORY_COLORS, CATEGORY_LABELS } from '../constants';

interface DashboardProps {
  profile: UserProfile;
  expenses: Expense[];
  onAddExpense: (amount: number, category: Category, description: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ profile, expenses, onAddExpense }) => {
  const totalExpenses = expenses.reduce((acc, curr) => acc + curr.amount, 0);
  const balance = profile.income - totalExpenses;

  const getCategoryTotal = (cat: Category) => 
    expenses.filter(e => e.category === cat).reduce((acc, curr) => acc + curr.amount, 0);

  const chartData = [
    { name: 'Necesidades', value: getCategoryTotal(Category.NEEDS), color: CATEGORY_COLORS.NEEDS },
    { name: 'Deseos', value: getCategoryTotal(Category.WANTS), color: CATEGORY_COLORS.WANTS },
    { name: 'Ahorro', value: getCategoryTotal(Category.SAVINGS), color: CATEGORY_COLORS.SAVINGS },
  ].filter(d => d.value > 0);

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Header Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex flex-col justify-between">
          <span className="text-slate-500 text-sm font-medium">Balance Actual</span>
          <div className="flex items-end gap-2 mt-2">
            <span className="text-3xl font-bold text-slate-900">${balance.toLocaleString()}</span>
            <span className={`text-xs font-bold px-2 py-1 rounded-full ${balance >= 0 ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-600'}`}>
              {balance >= 0 ? 'En verde' : 'Excedido'}
            </span>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex flex-col justify-between">
          <span className="text-slate-500 text-sm font-medium">Racha de Ahorro</span>
          <div className="flex items-center gap-3 mt-2">
            <div className="w-10 h-10 bg-orange-100 rounded-full flex items-center justify-center">
              <span className="text-xl">🔥</span>
            </div>
            <div>
              <span className="text-2xl font-bold text-slate-900">{profile.streak} días</span>
              <p className="text-xs text-slate-400">¡No pares ahora!</p>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex flex-col justify-between">
          <span className="text-slate-500 text-sm font-medium">Gastos Totales</span>
          <span className="text-3xl font-bold text-rose-600 mt-2">${totalExpenses.toLocaleString()}</span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Quick Add Expense */}
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Registrar Gasto</h3>
          <QuickExpenseForm onSubmit={onAddExpense} />
        </div>

        {/* Visual Summary */}
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Distribución Real</h3>
          <div className="h-[200px] w-full">
            {chartData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={chartData}
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                  >
                    {chartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }}
                  />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full text-slate-400 text-sm">
                No hay gastos registrados aún
              </div>
            )}
          </div>
          <div className="mt-4 flex justify-around text-xs font-medium">
            <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full" style={{backgroundColor: CATEGORY_COLORS.NEEDS}}/> Necesidades</div>
            <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full" style={{backgroundColor: CATEGORY_COLORS.WANTS}}/> Deseos</div>
            <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full" style={{backgroundColor: CATEGORY_COLORS.SAVINGS}}/> Ahorro</div>
          </div>
        </div>
      </div>
    </div>
  );
};

const QuickExpenseForm: React.FC<{ onSubmit: (a: number, c: Category, d: string) => void }> = ({ onSubmit }) => {
  const [amount, setAmount] = React.useState('');
  const [desc, setDesc] = React.useState('');
  const [cat, setCat] = React.useState<Category>(Category.NEEDS);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !desc) return;
    onSubmit(parseFloat(amount), cat, desc);
    setAmount('');
    setDesc('');
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="grid grid-cols-2 gap-4">
        <input 
          type="number" 
          placeholder="Monto" 
          value={amount} 
          onChange={e => setAmount(e.target.value)}
          className="bg-slate-50 border-none rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 outline-none"
        />
        <select 
          value={cat} 
          onChange={e => setCat(e.target.value as Category)}
          className="bg-slate-50 border-none rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 outline-none"
        >
          <option value={Category.NEEDS}>Necesidad</option>
          <option value={Category.WANTS}>Deseo</option>
          <option value={Category.SAVINGS}>Ahorro</option>
        </select>
      </div>
      <input 
        type="text" 
        placeholder="Descripción (ej. Supermercado)" 
        value={desc} 
        onChange={e => setDesc(e.target.value)}
        className="w-full bg-slate-50 border-none rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 outline-none"
      />
      <button type="submit" className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 transition-colors shadow-lg">
        Guardar Gasto
      </button>
    </form>
  );
};

export default Dashboard;

import React from 'react';
import { UserProfile, Expense, Category } from '../types';
import { CATEGORY_COLORS, CATEGORY_LABELS } from '../constants';

interface BudgetDetailsProps {
  profile: UserProfile;
  expenses: Expense[];
}

const BudgetDetails: React.FC<BudgetDetailsProps> = ({ profile, expenses }) => {
  const splits = {
    [Category.NEEDS]: profile.income * 0.50,
    [Category.WANTS]: profile.income * 0.30,
    [Category.SAVINGS]: profile.income * 0.20,
  };

  const getSpent = (cat: Category) => 
    expenses.filter(e => e.category === cat).reduce((acc, curr) => acc + curr.amount, 0);

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
        <h2 className="text-xl font-bold text-slate-800 mb-6">Tu Plan 50/30/20</h2>
        <div className="space-y-8">
          {(Object.keys(splits) as Category[]).map(cat => {
            const budget = splits[cat];
            const spent = getSpent(cat);
            const percentage = Math.min((spent / budget) * 100, 100);
            const isOver = spent > budget;

            return (
              <div key={cat} className="space-y-2">
                <div className="flex justify-between items-end">
                  <div>
                    <h4 className="font-bold text-slate-700">{CATEGORY_LABELS[cat]}</h4>
                    <p className="text-xs text-slate-400">Presupuesto: ${budget.toLocaleString()}</p>
                  </div>
                  <div className="text-right">
                    <span className={`text-lg font-bold ${isOver ? 'text-rose-500' : 'text-slate-800'}`}>
                      ${spent.toLocaleString()}
                    </span>
                    <p className="text-[10px] text-slate-400">Gastado</p>
                  </div>
                </div>
                <div className="h-4 w-full bg-slate-100 rounded-full overflow-hidden">
                  <div 
                    className="h-full transition-all duration-1000 ease-out"
                    style={{ 
                      width: `${percentage}%`, 
                      backgroundColor: isOver ? '#f43f5e' : CATEGORY_COLORS[cat]
                    }}
                  />
                </div>
                <div className="flex justify-between text-[10px] font-medium uppercase tracking-wider">
                  <span className={isOver ? 'text-rose-500' : 'text-slate-500'}>
                    {isOver ? `Excedido por $${(spent - budget).toLocaleString()}` : `${Math.round(percentage)}% utilizado`}
                  </span>
                  <span className="text-slate-500">Quedan ${(Math.max(0, budget - spent)).toLocaleString()}</span>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
        <h3 className="text-lg font-bold text-slate-800 mb-4">Últimos Movimientos</h3>
        <div className="space-y-3">
          {expenses.length === 0 ? (
            <p className="text-slate-400 text-sm text-center py-4">No hay gastos recientes.</p>
          ) : (
            expenses.slice().reverse().slice(0, 10).map(exp => (
              <div key={exp.id} className="flex items-center justify-between p-3 rounded-xl hover:bg-slate-50 transition-colors">
                <div className="flex items-center gap-3">
                  <div 
                    className="w-2 h-2 rounded-full" 
                    style={{ backgroundColor: CATEGORY_COLORS[exp.category] }}
                  />
                  <div>
                    <p className="text-sm font-semibold text-slate-700">{exp.description}</p>
                    <p className="text-[10px] text-slate-400">{new Date(exp.date).toLocaleDateString()}</p>
                  </div>
                </div>
                <span className="text-sm font-bold text-slate-900">-${exp.amount.toLocaleString()}</span>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default BudgetDetails;

