                    {isOver ? `Excedido por $${(spent - budget).toLocaleString()}` : `${Math.round(percentage)}% utilizado`}
                  </span>
                  <span className="text-slate-500">Saldo: ${(Math.max(0, budget - spent)).toLocaleString()}</span>
                </div>
