                  {tip.category === 'ahorro' ? '💰' : tip.category === 'inversion' ? '📈' : '🛑'}
                </div>
                <h3 className="text-lg font-bold text-slate-800 mb-2 group-hover:text-indigo-600 transition-colors">{tip.title}</h3>
