import React from 'react';
import { UserProfile, Expense, Category, Frequency } from '../types';
import { CATEGORY_COLORS, CATEGORY_LABELS, FREQUENCY_LABELS } from '../constants';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Legend,
  Cell
} from 'recharts';

interface BudgetDetailsProps {
  profile: UserProfile;
  expenses: Expense[];
}

const BudgetDetails: React.FC<BudgetDetailsProps> = ({ profile, expenses }) => {
  // Normalize income to Monthly for the 50/30/20 plan display
  const getMonthlyIncome = () => {
    switch (profile.frequency) {
      case Frequency.WEEKLY:
        return profile.income * 4.33; // Approx weeks in a month
      case Frequency.BIWEEKLY:
        return profile.income * 2;
      case Frequency.MONTHLY:
      default:
        return profile.income;
    }
  };

  const monthlyIncome = getMonthlyIncome();

  const splits = {
    [Category.NEEDS]: monthlyIncome * 0.50,
    [Category.WANTS]: monthlyIncome * 0.30,
    [Category.SAVINGS]: monthlyIncome * 0.20,
  };

  // For "Spent", we show total historical or periodic? 
  // Usually these apps show cumulative for current month.
  // For this version, we'll keep the current logic of all expenses to show against the monthly split.
  const getSpent = (cat: Category) => 
    expenses.filter(e => e.category === cat).reduce((acc, curr) => acc + curr.amount, 0);

  const chartData = [
    { 
      name: 'Necesidades', 
      Presupuesto: splits[Category.NEEDS], 
      Gastado: getSpent(Category.NEEDS),
      color: CATEGORY_COLORS.NEEDS 
    },
    { 
      name: 'Deseos', 
      Presupuesto: splits[Category.WANTS], 
      Gastado: getSpent(Category.WANTS),
      color: CATEGORY_COLORS.WANTS 
    },
    { 
      name: 'Ahorro', 
      Presupuesto: splits[Category.SAVINGS], 
      Gastado: getSpent(Category.SAVINGS),
      color: CATEGORY_COLORS.SAVINGS 
    },
  ];

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-white p-4 rounded-2xl shadow-xl border border-slate-100">
          <p className="text-sm font-bold text-slate-800 mb-2">{label}</p>
          <div className="space-y-1">
            <p className="text-xs text-slate-500 flex justify-between gap-4">
              <span>Mensual:</span> 
              <span className="font-bold text-slate-700">${payload[0].value.toLocaleString(undefined, { maximumFractionDigits: 0 })}</span>
            </p>
            <p className="text-xs text-slate-500 flex justify-between gap-4">
              <span>Gastado:</span> 
              <span className="font-bold text-indigo-600">${payload[1].value.toLocaleString(undefined, { maximumFractionDigits: 0 })}</span>
            </p>
          </div>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6">
      {/* Comparative Bar Chart Card */}
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
        <div className="flex justify-between items-start mb-6">
          <div>
            <h2 className="text-xl font-bold text-slate-800">Comparativa Mensual</h2>
            <div className="flex items-center gap-2 mt-1">
              <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">
                Presupuesto Mensual: ${monthlyIncome.toLocaleString(undefined, { maximumFractionDigits: 0 })}
              </span>
              <span className="text-[10px] bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full font-bold">
                Original: ${profile.income.toLocaleString()} {FREQUENCY_LABELS[profile.frequency]}
              </span>
            </div>
          </div>
        </div>
        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart
              data={chartData}
              margin={{ top: 20, right: 30, left: 0, bottom: 0 }}
              barGap={8}
            >
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis 
                dataKey="name" 
                axisLine={false} 
                tickLine={false} 
                tick={{ fill: '#64748b', fontSize: 12, fontWeight: 500 }}
                dy={10}
              />
              <YAxis 
                axisLine={false} 
                tickLine={false} 
                tick={{ fill: '#94a3b8', fontSize: 10 }}
                tickFormatter={(value) => `$${value}`}
              />
              <Tooltip cursor={{ fill: '#f8fafc' }} content={<CustomTooltip />} />
              <Legend 
                verticalAlign="top" 
                align="right" 
                iconType="circle"
                wrapperStyle={{ paddingBottom: '20px', fontSize: '12px', fontWeight: 600 }}
              />
              <Bar 
                name="Mensual" 
                dataKey="Presupuesto" 
                fill="#e2e8f0" 
                radius={[6, 6, 0, 0]} 
                barSize={32}
              />
              <Bar 
                name="Gastado" 
                dataKey="Gastado" 
                radius={[6, 6, 0, 0]} 
                barSize={32}
              >
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
        <h2 className="text-xl font-bold text-slate-800 mb-6">Detalle por Categoría (Mensual)</h2>
        <div className="space-y-8">
          {(Object.keys(splits) as Category[]).map(cat => {
            const budget = splits[cat];
            const spent = getSpent(cat);
            const percentage = Math.min((spent / budget) * 100, 100);
            const isOver = spent > budget;

            return (
              <div key={cat} className="space-y-2">
                <div className="flex justify-between items-end">
                  <div>
                    <h4 className="font-bold text-slate-700">{CATEGORY_LABELS[cat]}</h4>
                    <p className="text-xs text-slate-400">Objetivo Mensual: ${budget.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
                  </div>
                  <div className="text-right">
                    <span className={`text-lg font-bold ${isOver ? 'text-rose-500' : 'text-slate-800'}`}>
                      ${spent.toLocaleString()}
                    </span>
                    <p className="text-[10px] text-slate-400">Consumido</p>
                  </div>
                </div>
                <div className="h-4 w-full bg-slate-100 rounded-full overflow-hidden">
                  <div 
                    className="h-full transition-all duration-1000 ease-out"
                    style={{ 
                      width: `${percentage}%`, 
                      backgroundColor: isOver ? '#f43f5e' : CATEGORY_COLORS[cat]
                    }}
                  />
                </div>
                <div className="flex justify-between text-[10px] font-medium uppercase tracking-wider">
                  <span className={isOver ? 'text-rose-500' : 'text-slate-500'}>
                    {isOver ? `Excedido por $${(spent - budget).toLocaleString(undefined, { maximumFractionDigits: 0 })}` : `${Math.round(percentage)}% utilizado`}
                  </span>
                  <span className="text-slate-500">Saldo: ${(Math.max(0, budget - spent)).toLocaleString(undefined, { maximumFractionDigits: 0 })}</span>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
        <h3 className="text-lg font-bold text-slate-800 mb-4">Historial de Transacciones</h3>
        <div className="space-y-3">
          {expenses.length === 0 ? (
            <p className="text-slate-400 text-sm text-center py-4">Sin actividad reciente.</p>
          ) : (
            expenses.slice().reverse().slice(0, 10).map(exp => (
              <div key={exp.id} className="flex items-center justify-between p-3 rounded-xl hover:bg-slate-50 transition-colors">
                <div className="flex items-center gap-3">
                  <div 
                    className="w-2 h-2 rounded-full" 
                    style={{ backgroundColor: CATEGORY_COLORS[exp.category] }}
                  />
                  <div>
                    <p className="text-sm font-semibold text-slate-700">{exp.description}</p>
                    <p className="text-[10px] text-slate-400">{new Date(exp.date).toLocaleDateString()}</p>
                  </div>
                </div>
                <span className="text-sm font-bold text-slate-900">-${exp.amount.toLocaleString()}</span>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default BudgetDetails;

import React, { useState, useEffect } from 'react';
import { UserProfile, Expense, Frequency, Category, SavingsGoal } from './types';
import Onboarding from './components/Onboarding';
import Dashboard from './components/Dashboard';
import BudgetDetails from './components/BudgetDetails';
import LearningCenter from './components/LearningCenter';
import { FREQUENCY_LABELS } from './constants';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [goals, setGoals] = useState<SavingsGoal[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'budget' | 'learn'>('dashboard');

  // Load data from localStorage
  useEffect(() => {
    const savedProfile = localStorage.getItem('finanza_profile');
    const savedExpenses = localStorage.getItem('finanza_expenses');
    const savedGoals = localStorage.getItem('finanza_goals');

    if (savedProfile) {
      const parsedProfile = JSON.parse(savedProfile);
      const lastDate = new Date(parsedProfile.lastLoginDate);
      const today = new Date();
      const diffDays = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));

      if (diffDays === 1) {
        parsedProfile.streak += 1;
      } else if (diffDays > 1) {
        parsedProfile.streak = 1;
      }

      parsedProfile.lastLoginDate = today.toISOString();
      setProfile(parsedProfile);
    }

    if (savedExpenses) {
      setExpenses(JSON.parse(savedExpenses));
    }

    if (savedGoals) {
      setGoals(JSON.parse(savedGoals));
    }
  }, []);

  // Save data to localStorage
  useEffect(() => {
    if (profile) localStorage.setItem('finanza_profile', JSON.stringify(profile));
    if (expenses.length > 0) localStorage.setItem('finanza_expenses', JSON.stringify(expenses));
    if (goals.length >= 0) localStorage.setItem('finanza_goals', JSON.stringify(goals));
  }, [profile, expenses, goals]);

  const handleOnboardingComplete = (income: number, frequency: Frequency) => {
    const newProfile: UserProfile = {
      income,
      frequency,
      currency: 'USD',
      streak: 1,
      lastLoginDate: new Date().toISOString()
    };
    setProfile(newProfile);
  };

  const addExpense = (amount: number, category: Category, description: string) => {
    const newExpense: Expense = {
      id: Math.random().toString(36).substr(2, 9),
      amount,
      category,
      description,
      date: new Date().toISOString()
    };
    setExpenses([...expenses, newExpense]);
  };

  const updateGoals = (newGoals: SavingsGoal[]) => {
    setGoals(newGoals);
  };

  if (!profile) {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  const getMonthlyEquivalent = () => {
    switch (profile.frequency) {
      case Frequency.WEEKLY: return profile.income * 4.33;
      case Frequency.BIWEEKLY: return profile.income * 2;
      default: return profile.income;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-white border-b border-slate-100 sticky top-0 z-30 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
            <span className="text-white font-bold text-xs">ZC</span>
          </div>
          <h1 className="text-xl font-black text-slate-900 tracking-tight italic">ZCORPION</h1>
        </div>
        <div className="flex items-center gap-4">
          <div className="hidden md:block text-right">
            <p className="text-[10px] text-slate-400 font-bold uppercase">Tu Meta</p>
            <p className="text-sm font-bold text-slate-800">Libertad Financiera</p>
          </div>
          <div className="w-10 h-10 rounded-full bg-slate-100 overflow-hidden border-2 border-indigo-50">
