import React, { useState, useEffect } from 'react';
import { UserProfile, Expense, Frequency, Category, SavingsGoal } from './types';
import Onboarding from './components/Onboarding';
import Dashboard from './components/Dashboard';
import BudgetDetails from './components/BudgetDetails';
import LearningCenter from './components/LearningCenter';
import Settings from './components/Settings';
import { FREQUENCY_LABELS } from './constants';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [goals, setGoals] = useState<SavingsGoal[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'budget' | 'learn' | 'settings'>('dashboard');
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    return localStorage.getItem('finanza_dark_mode') === 'true';
  });

  // Load data from localStorage
  useEffect(() => {
    const savedProfile = localStorage.getItem('finanza_profile');
    const savedExpenses = localStorage.getItem('finanza_expenses');
    const savedGoals = localStorage.getItem('finanza_goals');

    if (savedProfile) {
      setProfile(JSON.parse(savedProfile));
    }

    if (savedExpenses) {
      setExpenses(JSON.parse(savedExpenses));
    }

    if (savedGoals) {
      setGoals(JSON.parse(savedGoals));
    }
  }, []);

  // Save data to localStorage
  useEffect(() => {
    if (profile) localStorage.setItem('finanza_profile', JSON.stringify(profile));
    if (expenses.length >= 0) localStorage.setItem('finanza_expenses', JSON.stringify(expenses));
    if (goals.length >= 0) localStorage.setItem('finanza_goals', JSON.stringify(goals));
    localStorage.setItem('finanza_dark_mode', isDarkMode.toString());
  }, [profile, expenses, goals, isDarkMode]);

  const handleOnboardingComplete = (income: number, frequency: Frequency) => {
    const newProfile: UserProfile = {
      income,
      frequency,
      currency: 'USD',
      streak: 0,
      lastLoginDate: new Date().toISOString()
    };
    setProfile(newProfile);
  };

  const addExpense = (amount: number, category: Category, description: string) => {
    const newExpense: Expense = {
      id: Math.random().toString(36).substr(2, 9),
      amount,
      category,
      description,
      date: new Date().toISOString()
    };

    const newExpenses = [...expenses, newExpense];
    setExpenses(newExpenses);

    // Streak logic: if it's a saving entry, we update the streak
    if (category === Category.SAVINGS && profile) {
      const today = new Date().toDateString();
      const lastSavingsDate = profile.lastLoginDate ? new Date(profile.lastLoginDate).toDateString() : "";

      let newStreak = profile.streak;
      if (today !== lastSavingsDate) {
        newStreak += 1;
      }

      setProfile({
        ...profile,
        streak: newStreak,
        lastLoginDate: new Date().toISOString()
      });
    }
  };

  const deleteExpense = (id: string) => {
    setExpenses(expenses.filter(e => e.id !== id));
  };

  const updateGoals = (newGoals: SavingsGoal[]) => {
    setGoals(newGoals);
  };

  const logout = () => {
    localStorage.removeItem('finanza_profile');
    localStorage.removeItem('finanza_expenses');
    localStorage.removeItem('finanza_goals');
    setProfile(null);
    setExpenses([]);
    setGoals([]);
    setActiveTab('dashboard');
  };

  if (!profile) {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  const getMonthlyEquivalent = () => {
    switch (profile.frequency) {
      case Frequency.WEEKLY: return profile.income * 4;
      case Frequency.BIWEEKLY: return profile.income * 2;
      default: return profile.income;
    }
  };

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-300 ${isDarkMode ? 'dark bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <header className={`border-b sticky top-0 z-30 px-6 py-4 flex items-center justify-between transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800 shadow-xl' : 'bg-white border-slate-100 shadow-sm'}`}>
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
            <span className="text-white font-bold text-xs">ZC</span>
          </div>
          <h1 className="text-xl font-black tracking-tight italic">ZCORPION</h1>
        </div>
        <div className="flex items-center gap-4">
          <div className="hidden md:block text-right">
            <p className="text-[10px] text-slate-400 font-bold uppercase">Tu Meta</p>
            <p className="text-sm font-bold">Libertad Financiera</p>
          </div>
          <button 
            onClick={() => setActiveTab('settings')}
            className={`w-10 h-10 rounded-full overflow-hidden border-2 flex items-center justify-center transition-colors ${isDarkMode ? 'bg-slate-800 border-indigo-900 hover:bg-slate-700' : 'bg-slate-100 border-indigo-50 hover:bg-slate-200'}`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-indigo-500" viewBox="0 0 20 20" fill="currentColor">
               <path fillRule="evenodd" d="M11.49 3.17c-.38-1.56-2.6-1.56-2.98 0a1.532 1.532 0 01-2.286.948c-1.372-.836-2.942.734-2.106 2.106.54.886.061 2.042-.947 2.287-1.561.379-1.561 2.6 0 2.978a1.532 1.532 0 01.947 2.287c-.836 1.372.734 2.942 2.106 2.106a1.532 1.532 0 012.287.947c.379 1.561 2.6 1.561 2.978 0a1.533 1.533 0 012.287-.947c1.372.836 2.942-.734 2.106-2.106a1.533 1.533 0 01.947-2.287c1.561-.379 1.561-2.6 0-2.978a1.532 1.532 0 01-.947-2.287c.836-1.372-.734-2.942-2.106-2.106a1.532 1.532 0 01-2.287-.947zM10 13a3 3 0 100-6 3 3 0 000 6z" clipRule="evenodd" />
            </svg>
          </button>
        </div>
      </header>

      <main className="flex-1 max-w-5xl w-full mx-auto p-4 md:p-6 mb-24">
        {activeTab !== 'settings' && (
          <div className="mb-8">
            <h2 className="text-3xl font-bold">Hola, Ahorrador 👋</h2>
            <div className="flex items-baseline gap-2 mt-1">
              <p className={`${isDarkMode ? 'text-slate-400' : 'text-slate-600'} font-medium`}>Presupuesto Mensual: ${getMonthlyEquivalent().toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">
                ({FREQUENCY_LABELS[profile.frequency]})
              </p>
            </div>
          </div>
        )}

        {activeTab === 'dashboard' && (
          <Dashboard profile={profile} expenses={expenses} onAddExpense={addExpense} isDarkMode={isDarkMode} />
        )}
        {activeTab === 'budget' && (
          <BudgetDetails profile={profile} expenses={expenses} onDeleteExpense={deleteExpense} isDarkMode={isDarkMode} />
        )}
        {activeTab === 'learn' && (
          <LearningCenter profile={profile} expenses={expenses} goals={goals} onUpdateGoals={updateGoals} isDarkMode={isDarkMode} />
        )}
        {activeTab === 'settings' && (
          <Settings 
            isDarkMode={isDarkMode} 
            toggleDarkMode={() => setIsDarkMode(!isDarkMode)} 
            onLogout={logout} 
          />
        )}
      </main>

      <nav className={`fixed bottom-0 left-0 right-0 border-t p-2 md:p-4 z-40 transition-colors backdrop-blur-md ${isDarkMode ? 'bg-slate-900/80 border-slate-800' : 'bg-white/80 border-slate-100'}`}>
        <div className="max-w-md mx-auto flex justify-around">
          <NavButton 
            active={activeTab === 'dashboard'} 
            onClick={() => setActiveTab('dashboard')}
            icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zM14 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z" /></svg>}
            label="Inicio"
          />
          <NavButton 
            active={activeTab === 'budget'} 
            onClick={() => setActiveTab('budget')}
            icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 3.055A9.001 9.001 0 1020.945 13H11V3.055z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.488 9H15V3.512A9.025 9.025 0 0120.488 9z" /></svg>}
            label="Plan 50/30/20"
          />
          <NavButton 
            active={activeTab === 'learn'} 
            onClick={() => setActiveTab('learn')}
            icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>}
            label="Aprende"
          />
        </div>
      </nav>
    </div>
  );
};

