import React from 'react';
import { UserProfile, Expense, Category } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { CATEGORY_COLORS, CATEGORY_LABELS } from '../constants';

interface DashboardProps {
  profile: UserProfile;
  expenses: Expense[];
  onAddExpense: (amount: number, category: Category, description: string) => void;
  isDarkMode: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ profile, expenses, onAddExpense, isDarkMode }) => {
  const totalExpenses = expenses.reduce((acc, curr) => acc + curr.amount, 0);
  const balance = profile.income - totalExpenses;

  const getCategoryTotal = (cat: Category) => 
    expenses.filter(e => e.category === cat).reduce((acc, curr) => acc + curr.amount, 0);

  const chartData = [
    { name: 'Necesidades', value: getCategoryTotal(Category.NEEDS), color: CATEGORY_COLORS.NEEDS },
    { name: 'Deseos', value: getCategoryTotal(Category.WANTS), color: CATEGORY_COLORS.WANTS },
    { name: 'Ahorro', value: getCategoryTotal(Category.SAVINGS), color: CATEGORY_COLORS.SAVINGS },
  ].filter(d => d.value > 0);

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Header Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className={`p-6 rounded-3xl border shadow-sm flex flex-col justify-between transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <span className="text-slate-500 text-sm font-medium uppercase tracking-wider">Balance Actual</span>
          <div className="flex items-end gap-2 mt-2">
            <span className="text-3xl font-bold">${balance.toLocaleString()}</span>
            <span className={`text-xs font-bold px-2 py-1 rounded-full ${balance >= 0 ? 'bg-emerald-500/10 text-emerald-500' : 'bg-rose-500/10 text-rose-500'}`}>
              {balance >= 0 ? 'En verde' : 'Excedido'}
            </span>
          </div>
        </div>

        <div className={`p-6 rounded-3xl border shadow-sm flex flex-col justify-between transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <span className="text-slate-500 text-sm font-medium uppercase tracking-wider">Racha de Ahorro</span>
          <div className="flex items-center gap-3 mt-2">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center ${isDarkMode ? 'bg-orange-500/20' : 'bg-orange-100'}`}>
              <span className="text-xl">🔥</span>
            </div>
            <div>
              <span className="text-2xl font-bold">{profile.streak} días</span>
              <p className="text-[10px] text-slate-400 font-bold uppercase">Meta: Registra ahorro hoy</p>
            </div>
          </div>
        </div>

        <div className={`p-6 rounded-3xl border shadow-sm flex flex-col justify-between transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <span className="text-slate-500 text-sm font-medium uppercase tracking-wider">Gastos Totales</span>
          <span className="text-3xl font-bold text-rose-500 mt-2">${totalExpenses.toLocaleString()}</span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Quick Add Expense */}
        <div className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <h3 className="text-lg font-bold mb-4">Registrar Movimiento</h3>
          <QuickExpenseForm onSubmit={onAddExpense} isDarkMode={isDarkMode} />
        </div>

        {/* Visual Summary */}
        <div className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <h3 className="text-lg font-bold mb-4">Distribución Real</h3>
          <div className="h-[200px] w-full">
            {chartData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={chartData}
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                    stroke="none"
                  >
                    {chartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip 
                    contentStyle={{ 
                      borderRadius: '16px', 
                      border: 'none', 
                      boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)',
                      backgroundColor: isDarkMode ? '#1e293b' : '#ffffff',
                      color: isDarkMode ? '#f1f5f9' : '#0f172a'
                    }}
                  />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full text-slate-500 text-sm italic">
                No hay movimientos registrados
              </div>
            )}
          </div>
          <div className="mt-4 flex justify-around text-[10px] font-bold uppercase tracking-widest text-slate-500">
            <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full" style={{backgroundColor: CATEGORY_COLORS.NEEDS}}/> Nec.</div>
            <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full" style={{backgroundColor: CATEGORY_COLORS.WANTS}}/> Deseos</div>
            <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full" style={{backgroundColor: CATEGORY_COLORS.SAVINGS}}/> Ahorro</div>
          </div>
        </div>
      </div>
    </div>
  );
};

const QuickExpenseForm: React.FC<{ onSubmit: (a: number, c: Category, d: string) => void, isDarkMode: boolean }> = ({ onSubmit, isDarkMode }) => {
  const [amount, setAmount] = React.useState('');
  const [desc, setDesc] = React.useState('');
  const [cat, setCat] = React.useState<Category>(Category.NEEDS);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !desc) return;
    onSubmit(parseFloat(amount), cat, desc);
    setAmount('');
    setDesc('');
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="grid grid-cols-2 gap-4">
        <input 
          type="number" 
          placeholder="Monto" 
          required
          value={amount} 
          onChange={e => setAmount(e.target.value)}
          className={`border-none rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 outline-none transition-colors ${isDarkMode ? 'bg-slate-800 text-white placeholder-slate-500' : 'bg-slate-50 placeholder-slate-400'}`}
        />
        <select 
          value={cat} 
          onChange={e => setCat(e.target.value as Category)}
          className={`border-none rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 outline-none transition-colors ${isDarkMode ? 'bg-slate-800 text-white' : 'bg-slate-50'}`}
        >
          <option value={Category.NEEDS}>Necesidad</option>
          <option value={Category.WANTS}>Deseo</option>
          <option value={Category.SAVINGS}>Ahorro</option>
        </select>
      </div>
      <input 
        type="text" 
        placeholder="Descripción (ej. Supermercado)" 
        required
        value={desc} 
        onChange={e => setDesc(e.target.value)}
        className={`w-full border-none rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 outline-none transition-colors ${isDarkMode ? 'bg-slate-800 text-white placeholder-slate-500' : 'bg-slate-50 placeholder-slate-400'}`}
      />
      <button type="submit" className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg active:scale-95">
        Guardar Transacción
      </button>
    </form>
  );
};

export default Dashboard;

import React from 'react';
import { UserProfile, Expense, Category, Frequency } from '../types';
import { CATEGORY_COLORS, CATEGORY_LABELS, FREQUENCY_LABELS } from '../constants';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Legend,
  Cell
} from 'recharts';

interface BudgetDetailsProps {
  profile: UserProfile;
  expenses: Expense[];
  onDeleteExpense: (id: string) => void;
  isDarkMode: boolean;
}

const BudgetDetails: React.FC<BudgetDetailsProps> = ({ profile, expenses, onDeleteExpense, isDarkMode }) => {
  // Normalize income to Monthly for the 50/30/20 plan display
  const getMonthlyIncome = () => {
    switch (profile.frequency) {
      case Frequency.WEEKLY:
        return profile.income * 4; // Week * 4
      case Frequency.BIWEEKLY:
        return profile.income * 2; // Biweekly * 2
      case Frequency.MONTHLY:
      default:
        return profile.income;
    }
  };

  const monthlyIncome = getMonthlyIncome();

  const splits = {
    [Category.NEEDS]: monthlyIncome * 0.50,
    [Category.WANTS]: monthlyIncome * 0.30,
    [Category.SAVINGS]: monthlyIncome * 0.20,
  };

  const getSpent = (cat: Category) => 
    expenses.filter(e => e.category === cat).reduce((acc, curr) => acc + curr.amount, 0);

  const chartData = [
    { 
      name: 'Necesidades', 
      Presupuesto: splits[Category.NEEDS], 
      Gastado: getSpent(Category.NEEDS),
      color: CATEGORY_COLORS.NEEDS 
    },
    { 
      name: 'Deseos', 
      Presupuesto: splits[Category.WANTS], 
      Gastado: getSpent(Category.WANTS),
      color: CATEGORY_COLORS.WANTS 
    },
    { 
      name: 'Ahorro', 
      Presupuesto: splits[Category.SAVINGS], 
      Gastado: getSpent(Category.SAVINGS),
      color: CATEGORY_COLORS.SAVINGS 
    },
  ];

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className={`p-4 rounded-2xl shadow-xl border transition-colors ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-100'}`}>
          <p className="text-sm font-bold mb-2">{label}</p>
          <div className="space-y-1">
            <p className="text-xs text-slate-500 flex justify-between gap-4">
              <span>Mensual:</span> 
              <span className={`font-bold ${isDarkMode ? 'text-slate-200' : 'text-slate-700'}`}>${payload[0].value.toLocaleString(undefined, { maximumFractionDigits: 0 })}</span>
            </p>
            <p className="text-xs text-slate-500 flex justify-between gap-4">
              <span>Gastado:</span> 
              <span className="font-bold text-indigo-500">${payload[1].value.toLocaleString(undefined, { maximumFractionDigits: 0 })}</span>
            </p>
          </div>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      {/* Comparative Bar Chart Card */}
      <div className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <div className="flex justify-between items-start mb-6">
          <div>
            <h2 className="text-xl font-bold">Comparativa Mensual</h2>
            <div className="flex flex-wrap items-center gap-2 mt-1">
              <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">
                Base Mensual: ${monthlyIncome.toLocaleString(undefined, { maximumFractionDigits: 0 })}
              </span>
              <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold uppercase transition-colors ${isDarkMode ? 'bg-slate-800 text-slate-400' : 'bg-slate-100 text-slate-500'}`}>
                Escala: ${profile.income.toLocaleString()} {FREQUENCY_LABELS[profile.frequency]}
              </span>
            </div>
          </div>
        </div>
        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart
              data={chartData}
              margin={{ top: 20, right: 30, left: 0, bottom: 0 }}
              barGap={8}
            >
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? "#1e293b" : "#f1f5f9"} />
              <XAxis 
                dataKey="name" 
                axisLine={false} 
                tickLine={false} 
                tick={{ fill: isDarkMode ? '#94a3b8' : '#64748b', fontSize: 12, fontWeight: 500 }}
                dy={10}
              />
              <YAxis 
                axisLine={false} 
                tickLine={false} 
                tick={{ fill: isDarkMode ? '#64748b' : '#94a3b8', fontSize: 10 }}
                tickFormatter={(value) => `$${value}`}
              />
              <Tooltip cursor={{ fill: isDarkMode ? '#1e293b' : '#f8fafc' }} content={<CustomTooltip />} />
              <Legend 
                verticalAlign="top" 
                align="right" 
                iconType="circle"
                wrapperStyle={{ paddingBottom: '20px', fontSize: '10px', fontWeight: 600, textTransform: 'uppercase' }}
              />
              <Bar 
                name="Mensual" 
                dataKey="Presupuesto" 
                fill={isDarkMode ? "#334155" : "#e2e8f0"} 
                radius={[6, 6, 0, 0]} 
                barSize={32}
              />
              <Bar 
                name="Gastado" 
                dataKey="Gastado" 
                radius={[6, 6, 0, 0]} 
                barSize={32}
              >
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <h2 className="text-xl font-bold mb-6">Detalle por Categoría (Mensual)</h2>
        <div className="space-y-8">
          {(Object.keys(splits) as Category[]).map(cat => {
            const budget = splits[cat];
            const spent = getSpent(cat);
            const percentage = Math.min((spent / budget) * 100, 100);
            const isOver = spent > budget;

            return (
              <div key={cat} className="space-y-2">
                <div className="flex justify-between items-end">
                  <div>
                    <h4 className={`font-bold uppercase tracking-wide text-sm ${isDarkMode ? 'text-slate-300' : 'text-slate-700'}`}>{CATEGORY_LABELS[cat]}</h4>
                    <p className="text-[10px] font-bold text-slate-500 uppercase">Límite: ${budget.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
                  </div>
                  <div className="text-right">
                    <span className={`text-lg font-bold ${isOver ? 'text-rose-500' : ''}`}>
                      ${spent.toLocaleString()}
                    </span>
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Utilizado</p>
                  </div>
                </div>
                <div className={`h-3 w-full rounded-full overflow-hidden transition-colors ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
                  <div 
                    className="h-full transition-all duration-1000 ease-out"
                    style={{ 
                      width: `${percentage}%`, 
                      backgroundColor: isOver ? '#f43f5e' : CATEGORY_COLORS[cat]
                    }}
                  />
                </div>
                <div className="flex justify-between text-[10px] font-bold uppercase tracking-widest">
                  <span className={isOver ? 'text-rose-500' : 'text-slate-500'}>
                    {isOver ? `Exceso: $${(spent - budget).toLocaleString(undefined, { maximumFractionDigits: 0 })}` : `${Math.round(percentage)}%`}
                  </span>
                  <span className="text-slate-500">Disponible: ${(Math.max(0, budget - spent)).toLocaleString(undefined, { maximumFractionDigits: 0 })}</span>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <div className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <h3 className="text-lg font-bold mb-4">Historial de Transacciones</h3>
        <div className="space-y-3">
          {expenses.length === 0 ? (
            <p className="text-slate-500 text-sm text-center py-8 italic font-medium">Sin actividad reciente.</p>
          ) : (
            expenses.slice().reverse().map(exp => (
              <div key={exp.id} className={`flex items-center justify-between p-3 rounded-xl transition-all hover:translate-x-1 ${isDarkMode ? 'hover:bg-slate-800' : 'hover:bg-slate-50'}`}>
                <div className="flex items-center gap-3">
                  <div 
                    className="w-2 h-2 rounded-full shadow-sm" 
                    style={{ backgroundColor: CATEGORY_COLORS[exp.category] }}
                  />
                  <div>
                    <p className="text-sm font-bold">{exp.description}</p>
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-tighter">{new Date(exp.date).toLocaleDateString()} • {CATEGORY_LABELS[exp.category]}</p>
                  </div>
                </div>
                <div className="flex items-center gap-4">
                  <span className="text-sm font-black">-${exp.amount.toLocaleString()}</span>
                  <button 
                    onClick={() => onDeleteExpense(exp.id)}
                    className={`p-2 rounded-lg transition-colors hover:text-rose-500 ${isDarkMode ? 'text-slate-600' : 'text-slate-300'}`}
                    title="Eliminar gasto"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                    </svg>
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default BudgetDetails;

import React, { useEffect, useState } from 'react';
import { getFinancialAdvice } from '../services/geminiService';
import { UserProfile, Expense, SavingsGoal } from '../types';

interface LearningCenterProps {
  profile: UserProfile;
  expenses: Expense[];
  goals: SavingsGoal[];
  onUpdateGoals: (goals: SavingsGoal[]) => void;
  isDarkMode: boolean;
}

interface Tip {
  title: string;
  content: string;
  category: 'ahorro' | 'inversion' | 'gasto';
}

const LearningCenter: React.FC<LearningCenterProps> = ({ profile, expenses, goals, onUpdateGoals, isDarkMode }) => {
  const [tips, setTips] = useState<Tip[]>([]);
  const [loading, setLoading] = useState(true);
  const [showGoalForm, setShowGoalForm] = useState(false);
  const [goalName, setGoalName] = useState('');
  const [goalAmount, setGoalAmount] = useState('');

  useEffect(() => {
    const fetchTips = async () => {
      setLoading(true);
      const advice = await getFinancialAdvice(profile, expenses, goals);
      setTips(advice);
      setLoading(false);
    };
    fetchTips();
  }, [profile, expenses, goals]);

  const handleAddGoal = (e: React.FormEvent) => {
    e.preventDefault();
    if (!goalName || !goalAmount) return;
    const newGoal: SavingsGoal = {
      id: Math.random().toString(36).substr(2, 9),
      name: goalName,
      targetAmount: parseFloat(goalAmount),
      currentAmount: 0
    };
    onUpdateGoals([...goals, newGoal]);
    setGoalName('');
    setGoalAmount('');
    setShowGoalForm(false);
  };

  const handleUpdateProgress = (id: string, amount: string) => {
    const value = parseFloat(amount);
    if (isNaN(value)) return;
    const newGoals = goals.map(g => 
      g.id === id ? { ...g, currentAmount: g.currentAmount + value } : g
    );
    onUpdateGoals(newGoals);
  };

  const handleDeleteGoal = (id: string) => {
    onUpdateGoals(goals.filter(g => g.id !== id));
  };

  return (
    <div className="space-y-8 pb-20 animate-in fade-in duration-500">
      {/* AI Tips Section */}
      <section>
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-2xl font-bold">Consejos de IA Personalizados</h2>
          <button 
            onClick={() => window.location.reload()}
            className="text-indigo-500 text-sm font-bold hover:underline uppercase tracking-widest"
          >
            Refrescar
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {loading ? (
            Array(3).fill(0).map((_, i) => (
              <div key={i} className={`h-64 animate-pulse rounded-3xl ${isDarkMode ? 'bg-slate-800' : 'bg-slate-200'}`} />
            ))
          ) : (
            tips.map((tip, idx) => (
              <div key={idx} className={`p-6 rounded-3xl border shadow-sm group hover:shadow-xl transition-all duration-300 ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center mb-4 transition-colors ${
                  tip.category === 'ahorro' ? 'bg-emerald-500/10 text-emerald-500' :
                  tip.category === 'inversion' ? 'bg-indigo-500/10 text-indigo-500' :
                  'bg-orange-500/10 text-orange-500'
                }`}>
                  {tip.category === 'ahorro' ? '💰' : tip.category === 'inversion' ? '📈' : '🛑'}
                </div>
                <h3 className="text-lg font-bold mb-2 group-hover:text-indigo-500 transition-colors">{tip.title}</h3>
                <p className={`text-sm leading-relaxed ${isDarkMode ? 'text-slate-400' : 'text-slate-500'}`}>{tip.content}</p>
              </div>
            ))
          )}
        </div>
      </section>

      {/* Savings Goals Section */}
      <section className={`p-8 rounded-[2rem] border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
          <div>
            <h2 className="text-2xl font-bold">Tus Metas de Ahorro</h2>
            <p className="text-sm text-slate-500 font-medium">Invierte en tu futuro, una meta a la vez.</p>
          </div>
          <button 
            onClick={() => setShowGoalForm(!showGoalForm)}
            className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold text-sm hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 shadow-lg active:scale-95"
          >
            {showGoalForm ? 'Cerrar' : '+ Nueva Meta'}
          </button>
        </div>

        {showGoalForm && (
          <form onSubmit={handleAddGoal} className={`mb-8 p-6 rounded-2xl border transition-colors animate-in slide-in-from-top duration-300 ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-200'}`}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Nombre de la Meta</label>
                <input 
                  type="text" 
                  placeholder="Ej. Viaje a Japón" 
                  value={goalName}
                  required
                  onChange={e => setGoalName(e.target.value)}
                  className={`w-full border-none rounded-xl p-3 outline-none focus:ring-2 focus:ring-indigo-500 transition-colors ${isDarkMode ? 'bg-slate-700 text-white placeholder-slate-500' : 'bg-white text-slate-900 placeholder-slate-400'}`}
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Monto Objetivo</label>
                <input 
                  type="number" 
                  placeholder="Monto total" 
                  value={goalAmount}
                  required
                  onChange={e => setGoalAmount(e.target.value)}
                  className={`w-full border-none rounded-xl p-3 outline-none focus:ring-2 focus:ring-indigo-500 transition-colors ${isDarkMode ? 'bg-slate-700 text-white placeholder-slate-500' : 'bg-white text-slate-900 placeholder-slate-400'}`}
                />
              </div>
            </div>
            <button type="submit" className="mt-4 w-full bg-indigo-600 text-white py-4 rounded-xl font-bold hover:bg-indigo-700 transition-colors shadow-lg">
              Establecer Meta
            </button>
          </form>
        )}

        <div className="space-y-6">
          {goals.length === 0 ? (
            <div className={`text-center py-12 rounded-2xl border border-dashed transition-colors ${isDarkMode ? 'bg-slate-800/50 border-slate-700' : 'bg-slate-50 border-slate-200'}`}>
              <p className="text-slate-500 font-medium italic">Define tus sueños para empezar a ahorrar.</p>
            </div>
          ) : (
            goals.map(goal => {
              const percentage = Math.min((goal.currentAmount / goal.targetAmount) * 100, 100);
              return (
                <div key={goal.id} className={`p-6 rounded-2xl border transition-colors ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-200'}`}>
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h4 className="text-lg font-black uppercase tracking-tight italic">{goal.name}</h4>
                      <p className="text-xs text-slate-500 font-bold uppercase tracking-wider">
                        ${goal.currentAmount.toLocaleString()} de ${goal.targetAmount.toLocaleString()} ahorrados
                      </p>
                    </div>
                    <button 
                      onClick={() => handleDeleteGoal(goal.id)}
                      className="text-slate-400 hover:text-rose-500 transition-colors p-1"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
                      </svg>
                    </button>
                  </div>

                  <div className={`h-4 w-full rounded-full overflow-hidden mb-6 shadow-inner ${isDarkMode ? 'bg-slate-700' : 'bg-slate-200'}`}>
                    <div 
                      className="h-full bg-emerald-500 transition-all duration-1000 ease-out shadow-[0_0_10px_rgba(16,185,129,0.5)]"
                      style={{ width: `${percentage}%` }}
                    />
                  </div>

                  <div className="flex gap-2">
                    <input 
                      type="number" 
                      placeholder="Cantidad a sumar" 
                      className={`flex-1 border border-none rounded-xl px-4 text-sm outline-none focus:ring-2 focus:ring-emerald-500 transition-colors ${isDarkMode ? 'bg-slate-700 text-white' : 'bg-white'}`}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') {
                          handleUpdateProgress(goal.id, (e.target as HTMLInputElement).value);
                          (e.target as HTMLInputElement).value = '';
                        }
                      }}
                    />
                    <button 
                      onClick={(e) => {
                        const input = (e.currentTarget.previousSibling as HTMLInputElement);
                        handleUpdateProgress(goal.id, input.value);
                        input.value = '';
                      }}
                      className="bg-emerald-500 text-white px-6 py-2 rounded-xl font-bold text-xs hover:bg-emerald-600 transition-all shadow-md active:scale-95"
                    >
                      Sumar
                    </button>
                  </div>
                </div>
              );
            })
          )}
        </div>
      </section>

      {/* Investment Intro Section */}
      <section className="bg-slate-900 rounded-[2rem] p-8 text-white relative overflow-hidden shadow-2xl">
        <div className="relative z-10">
          <h3 className="text-2xl font-black mb-6 italic tracking-tight">Primeros pasos para invertir</h3>
          <div className="space-y-8">
            <div className="flex gap-4">
              <div className="flex-shrink-0 w-10 h-10 rounded-xl bg-emerald-500/20 flex items-center justify-center font-black text-emerald-400 border border-emerald-500/30">1</div>
              <div>
                <h4 className="font-bold text-emerald-400 uppercase text-xs tracking-widest mb-1">Fondo de Seguridad</h4>
                <p className="text-sm text-slate-400 leading-relaxed">Antes de invertir, asegura un colchón de 3 meses. Es tu paracaídas financiero.</p>
              </div>
            </div>
            <div className="flex gap-4">
              <div className="flex-shrink-0 w-10 h-10 rounded-xl bg-indigo-500/20 flex items-center justify-center font-black text-indigo-400 border border-indigo-500/30">2</div>
              <div>
                <h4 className="font-bold text-indigo-400 uppercase text-xs tracking-widest mb-1">Interés Compuesto</h4>
                <p className="text-sm text-slate-400 leading-relaxed">No importa cuánto, importa cuándo. Empezar hoy es mejor que empezar mañana con el doble.</p>
              </div>
            </div>
          </div>
        </div>
        <div className="absolute -right-20 -bottom-20 w-80 h-80 bg-indigo-600/10 rounded-full blur-[100px]"></div>
        <div className="absolute -left-20 -top-20 w-64 h-64 bg-emerald-600/10 rounded-full blur-[80px]"></div>
      </section>
    </div>
  );
};

